import React, { useState, useEffect } from 'react';
import {
  Box,
  Paper,
  TextField,
  Button,
  Typography,
  Link,
  Alert,
  CircularProgress,
  Container,
  InputAdornment,
  IconButton
} from '@mui/material';
import {
  Visibility,
  VisibilityOff,
  Email,
  Lock
} from '@mui/icons-material';
import { Link as RouterLink } from 'react-router-dom';
import { toast } from 'react-toastify';
import { useAuth } from '../../contexts/AuthContext';

const Login = () => {
  const { login } = useAuth();
  const [formData, setFormData] = useState({
    email: '',
    password: ''
  });
  const [showPassword, setShowPassword] = useState(false);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');
  const [displayText, setDisplayText] = useState('');
  const [isTyping, setIsTyping] = useState(true);
  const [showDots, setShowDots] = useState(false);

  const fullText = 'Nautilus Automação';
  const typingSpeed = 150; // velocidade de digitação em ms
  const pauseTime = 10000; // pausa de 10 segundos

  // Logos de criptomoedas (caminhos para os arquivos SVG)
  // Certifique-se de que estes arquivos SVG existem em 'src/assets/crypto_logos/'
  const cryptoLogos = [
    'assets/crypto_logos/btc.svg', // Exemplo: Bitcoin
    'assets/crypto_logos/eth.svg', // Exemplo: Ethereum
    'assets/crypto_logos/ltc.svg', // Exemplo: Litecoin
    'assets/crypto_logos/doge.svg', // Exemplo: Dogecoin
    'assets/crypto_logos/ada.svg', // Exemplo: Cardano
    // Adicione mais logos conforme necessário
  ];
  // Se você não tiver os logos acima, pode usar estes como placeholder, mas não são logos reais:
  const cryptoSymbols = ['₿', '⟠', '◊', '⧫', '◈', '◇', '⬟', '⬢', '⬡', '⬠', '⟐', '⟡', '⟢', '⟣', '⟤', '⟥', '⟦', '⟧', '⟨', '⟩'];

  useEffect(() => {
    let timeoutId;
    let currentIndex = 0;

    const typeText = () => {
      if (currentIndex <= fullText.length) {
        setDisplayText(fullText.slice(0, currentIndex));
        currentIndex++;
        timeoutId = setTimeout(typeText, typingSpeed);
      } else {
        setIsTyping(false);
        setShowDots(true);

        // Após mostrar os pontos por um tempo, reinicia o ciclo
        timeoutId = setTimeout(() => {
          setShowDots(false);
          setIsTyping(true);
          setDisplayText('');
          currentIndex = 0;
          typeText();
        }, pauseTime);
      }
    };

    typeText();

    return () => {
      if (timeoutId) {
        clearTimeout(timeoutId);
      }
    };
  }, []);

  // Função para gerar logos flutuantes
  const generateFloatingSymbols = () => {
    const symbols = [];
    const numSymbols = 75; // Aumente ou diminua para mais/menos densidade

    // Verifique se cryptoLogos está definido e tem itens, caso contrário, use os símbolos de texto como fallback
    const logosToUse = (typeof cryptoLogos !== 'undefined' && cryptoLogos.length > 0) 
                       ? cryptoLogos 
                       : (typeof cryptoSymbols !== 'undefined' ? cryptoSymbols : []);
    const isSvg = typeof cryptoLogos !== 'undefined' && cryptoLogos.length > 0;

    if (logosToUse.length === 0) return null; // Não renderizar nada se não houver logos/símbolos

    for (let i = 0; i < numSymbols; i++) {
      const logoSrcOrSymbol = logosToUse[Math.floor(Math.random() * logosToUse.length)];
      const delay = Math.random() * 20; // Atraso maior para espalhar mais a aparição
      const duration = 20 + Math.random() * 15; // Duração da animação
      const size = 30 + Math.random() * 40; // Tamanho dos logos
      const initialLeft = Math.random() * 100; // Posição horizontal inicial em vw
      const opacity = 0.3 + Math.random() * 0.5; // Opacidade

      symbols.push(
        <Box
          key={`crypto-logo-${i}`}
          sx={{
            position: 'absolute',
            bottom: `-${size}px`, // Começa abaixo da tela
            left: `${initialLeft}vw`, // Usa vw para cobrir a largura da viewport
            width: `${size}px`,
            height: `${size}px`,
            opacity: opacity,
            animation: `moveUp ${duration}s linear infinite`,
            animationDelay: `${delay}s`,
            userSelect: 'none',
            pointerEvents: 'none',
            zIndex: 0, // Atrás do conteúdo principal
            transform: 'translateX(-50%)', // Centraliza o logo em sua posição 'left'
          }}
        >
          {isSvg ? (
            <img src={logoSrcOrSymbol} alt="crypto logo" style={{ width: '100%', height: '100%' }} />
          ) : (
            <Typography sx={{ fontSize: `${size}px`, color: '#1976d2' }}>{logoSrcOrSymbol}</Typography>
          )}
        </Box>
      );
    }
    return symbols;
  };

  const handleChange = (e) => {
    const { name, value } = e.target;
    setFormData(prev => ({
      ...prev,
      [name]: value
    }));
    // Limpar erro quando o usuário começar a digitar
    if (error) setError('');
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    setError('');

    // Validação básica
    if (!formData.email || !formData.password) {
      setError('Todos os campos são obrigatórios');
      setLoading(false);
      return;
    }

    // Validação simples de email
    const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    if (!emailRegex.test(formData.email)) {
      setError('Formato de email inválido');
      setLoading(false);
      return;
    }

    try {
      const result = await login(formData.email, formData.password);

      if (result.success) {
        toast.success('Login realizado com sucesso!');
      } else {
        setError(result.message || 'Erro ao fazer login');
        toast.error(result.message || 'Erro ao fazer login');
      }
    } catch (error) {
      console.error('Erro no login:', error);
      setError('Erro ao fazer login. Tente novamente.');
      toast.error('Erro ao fazer login');
    } finally {
      setLoading(false);
    }
  };

  const togglePasswordVisibility = () => {
    setShowPassword(!showPassword);
  };

  return (
    <Box
      sx={{
        position: 'relative',
        minHeight: '100vh',
        overflow: 'hidden',
        background: 'linear-gradient(135deg, #f5f7fa 0%, #c3cfe2 100%)'
      }}
    >
      {/* Background com símbolos flutuantes */}
      <Box
        sx={{
          position: 'fixed', // Mantém fixo para cobrir a tela toda
          top: 0,
          left: 0,
          width: '100vw', // Usa vw para largura total da viewport
          height: '100vh', // Usa vh para altura total da viewport
          zIndex: 0, // Garante que está atrás do conteúdo
          overflow: 'hidden', // Essencial para não criar barras de rolagem
          pointerEvents: 'none' // Para não interferir com cliques no formulário
        }}
      >
        {generateFloatingSymbols()}
      </Box>

      {/* CSS para animações */}
      <style>
        {`
          @keyframes blink {
            0%, 50% { opacity: 1; }
            51%, 100% { opacity: 0; }
          }
          @keyframes blinkDots {
            0%, 33% { opacity: 1; }
            34%, 66% { opacity: 0.5; }
            67%, 100% { opacity: 0; }
          }
          @keyframes moveUp {
            0% {
              transform: translateY(0px) translateX(-50%) rotate(0deg); 
              opacity: 0.3;
            }
            50% {
              opacity: 0.8;
            }
            100% {
              transform: translateY(-110vh) translateX(-50%) rotate(360deg); 
              opacity: 0.1;
            }
          }
        `}
      </style>

      <Container maxWidth="sm" sx={{ position: 'relative', zIndex: 1 }}>
        <Box
          sx={{
            minHeight: '100vh',
            display: 'flex',
            alignItems: 'center',
            justifyContent: 'center',
            py: 4
          }}
        >
          <Paper
            elevation={8}
            sx={{
              p: 4,
              width: '100%',
              maxWidth: 400,
              bgcolor: 'rgba(255, 255, 255, 0.95)',
              borderRadius: 2,
              backdropFilter: 'blur(10px)'
            }}
          >
            {/* Logo/Título */}
            <Box sx={{ textAlign: 'center', mb: 4 }}>
              <Typography
                variant="h5"
                component="h1"
                sx={{
                  fontWeight: 'bold',
                  color: '#1976d2', // Cor azul
                  mb: 1,
                  minHeight: '2rem', // Altura mínima para evitar saltos
                  display: 'flex',
                  alignItems: 'center',
                  justifyContent: 'center',
                  fontSize: '1.5rem',
                  whiteSpace: 'nowrap'
                }}
              >
                {displayText}
                {isTyping && (
                  <Box
                    component="span"
                    sx={{
                      display: 'inline-block',
                      width: '2px',
                      height: '1.2em',
                      backgroundColor: '#1976d2',
                      marginLeft: '2px',
                      animation: 'blink 1s infinite'
                    }}
                  />
                )}
                {showDots && (
                  <Box
                    component="span"
                    sx={{
                      color: '#1976d2',
                      marginLeft: '8px',
                      animation: 'blinkDots 1.5s infinite'
                    }}
                  >
                    ...
                  </Box>
                )}
              </Typography>
              <Typography
                variant="subtitle1"
                color="text.secondary"
              >
                Faça login em sua conta
              </Typography>
            </Box>

            {/* Formulário */}
            <Box component="form" onSubmit={handleSubmit}>
              {error && (
                <Alert severity="error" sx={{ mb: 2 }}>
                  {error}
                </Alert>
              )}

              <TextField
                fullWidth
                name="email"
                label="Email"
                type="email"
                value={formData.email}
                onChange={handleChange}
                margin="normal"
                required
                autoComplete="email"
                autoFocus
                InputProps={{
                  startAdornment: (
                    <InputAdornment position="start">
                      <Email color="action" />
                    </InputAdornment>
                  ),
                }}
                sx={{
                  '& .MuiOutlinedInput-root': {
                    '&:hover fieldset': {
                      borderColor: '#1976d2', // Cor azul
                    },
                    '&.Mui-focused fieldset': {
                      borderColor: '#1976d2', // Cor azul
                    },
                  },
                  '& .MuiInputLabel-root.Mui-focused': {
                    color: '#1976d2', // Cor azul
                  },
                }}
              />

              <TextField
                fullWidth
                name="password"
                label="Senha"
                type={showPassword ? 'text' : 'password'}
                value={formData.password}
                onChange={handleChange}
                margin="normal"
                required
                autoComplete="current-password"
                InputProps={{
                  startAdornment: (
                    <InputAdornment position="start">
                      <Lock color="action" />
                    </InputAdornment>
                  ),
                  endAdornment: (
                    <InputAdornment position="end">
                      <IconButton
                        onClick={togglePasswordVisibility}
                        edge="end"
                        aria-label="toggle password visibility"
                      >
                        {showPassword ? <VisibilityOff /> : <Visibility />}
                      </IconButton>
                    </InputAdornment>
                  ),
                }}
                sx={{
                  '& .MuiOutlinedInput-root': {
                    '&:hover fieldset': {
                      borderColor: '#1976d2', // Cor azul
                    },
                    '&.Mui-focused fieldset': {
                      borderColor: '#1976d2', // Cor azul
                    },
                  },
                  '& .MuiInputLabel-root.Mui-focused': {
                    color: '#1976d2', // Cor azul
                  },
                }}
              />

              <Button
                type="submit"
                fullWidth
                variant="contained"
                disabled={loading}
                sx={{
                  mt: 3,
                  mb: 2,
                  py: 1.5,
                  fontSize: '1rem',
                  fontWeight: 'bold',
                  bgcolor: '#1976d2', // Cor azul
                  color: 'white',
                  '&:hover': {
                    bgcolor: '#1565c0', // Azul mais escuro no hover
                  },
                  '&:disabled': {
                    bgcolor: 'action.disabled',
                  },
                }}
              >
                {loading ? (
                  <CircularProgress size={24} color="inherit" />
                ) : (
                  'Entrar'
                )}
              </Button>

              {/* Link para registro */}
              <Box sx={{ textAlign: 'center', mt: 2 }}>
                <Typography variant="body2" color="text.secondary">
                  Não tem uma conta?{' '}
                  <Link
                    component={RouterLink}
                    to="/register"
                    sx={{
                      color: '#1976d2', // Cor azul
                      textDecoration: 'none',
                      fontWeight: 'bold',
                      '&:hover': {
                        textDecoration: 'underline',
                      },
                    }}
                  >
                    Registre-se
                  </Link>
                </Typography>
              </Box>
            </Box>
          </Paper>
        </Box>
      </Container>
    </Box>
  );
};

export default Login;
